import{wireIntake}from"./intake";import{hydratePage}from"./pages";import{PageRoutes}from"./routes";function wireScrollReveal(){const e=()=>{const e=document.querySelectorAll(".scroll-reveal"),t=.9*window.innerHeight;e.forEach((e=>{e.getBoundingClientRect().top<t&&e.classList.add("visible")}))};e(),window.addEventListener("scroll",e,{passive:!0})}function wireActiveNav(e){const t={home:PageRoutes.home,"hire-direct":PageRoutes.hireDirect,portfolios:PageRoutes.portfolios,freelancer:PageRoutes.freelancer,"client-dashboard":PageRoutes.clientDashboard,"freelancer-dashboard":PageRoutes.freelancerDashboard}[e]??"";document.querySelectorAll(".nav-links .nav-item").forEach((e=>{(e.getAttribute("href")??"")===t&&e.classList.add("active")}))}async function boot(){const e=document.body.dataset.page??"home";wireActiveNav(e),wireScrollReveal(),await Promise.all([wireIntake(),hydratePage(e)])}boot();